/*AcenMapper.getMnpLimitDayCnt*/
SELECT COUNT(DTL_CD)
FROM NMCP_CD_DTL
WHERE CD_GROUP_ID = 'AcenMnpLimit'
  AND EXPNSN_STR_VAL1 = #{nowDate}
  AND USE_YN = 'Y'

mapper.update:
/*AcenMapper.updateAcenTrg*/ UPDATE NMCP_ACEN_REQ SET END_STATUS = 'P' WHERE REQUEST_KEY IN ( SELECT REQUEST_KEY FROM ( WITH ACEN_REQ AS ( SELECT REQUEST_KEY, EVNT_TYPE, REGST_DTTM FROM NMCP_ACEN_REQ WHERE NVL(RTY_DT, REGST_DT) BETWEEN TO_CHAR(SYSDATE-14, 'YYYYMMDD') AND TO_CHAR(SYSDATE, 'YYYYMMDD') AND END_STATUS = 'N' AND REQ_STATUS != 'Y' /*상담사 신규가입 제외*/
AND EVNT_GRP_CD != 'NEW_NOSIM' AND EVNT_GRP_CD != 'NEW_SIM'
/*상담사 번호이동 제외*/
AND EVNT_GRP_CD != 'MNP_NOSIM' AND EVNT_GRP_CD != 'MNP_SIM'
/*셀프개통 사후해피콜 제외*/
AND EVNT_GRP_CD != 'SLF_CST'
) SELECT A.REQUEST_KEY, A.REGST_DTTM FROM ACEN_REQ A, MCP_REQUEST B WHERE A.REQUEST_KEY = B.REQUEST_KEY AND EXISTS ( SELECT 1 FROM NMCP_CD_DTL WHERE CD_GROUP_ID = 'AcenReqStateCd' AND EXPNSN_STR_VAL1 = A.EVNT_TYPE AND EXPNSN_STR_VAL2 = B.PSTATE AND EXPNSN_STR_VAL3 = B.REQUEST_STATE_CODE ) ORDER BY A.REGST_DTTM ) WHERE ROWNUM <= #{count} )

/*AcenMapper.updateAcenReqInfo*/
UPDATE NMCP_ACEN_REQ
SET RVISN_ID = 'ACEN01'
   ,RVISN_DTTM = SYSDATE

   ,REQ_STATUS = #{reqStatus}


   ,END_STATUS = #{endStatus}


   ,SUCC_YN = #{succYn}


   ,PRE_CHECK_YN = #{preCheckYn}


   ,OPEN_YN = #{openYn}


   ,RMK = #{rmk}

WHERE REQUEST_KEY = #{requestKey}

/*AcenMapper.updateMcpReqInfo*/
UPDATE MCP_REQUEST
SET RVISN_ID = 'ACEN'
   ,RVISN_DTTM = SYSDATE

   ,PSTATE = #{pstate}


   ,REQUEST_STATE_CODE = #{requestStateCode}

WHERE REQUEST_KEY = #{requestKey}

