/*AcenMapper.getPreCheckSuccessCnt*/ SELECT COUNT(MVNO_ORD_NO) FROM MCP_REQUEST_OSST WHERE MVNO_ORD_NO = LPAD(#{resNo}, 14, '0') AND PRGR_STAT_CD = #{prgrStatCd}
AND RSLT_CD = '0000' AND SUBSTR(RSLT_DT, 1,8) = TO_CHAR(SYSDATE, 'YYYYMMDD')
AND RSLT_CD IN ('0000', '3060', '3070')
